#include <iostream>
#include <string>
#include <string_view>
#include <vector>
#include <memory>

class Animal
{
public:
    virtual std::string_view speak() const { return "..."; }
};

class Cat : public Animal
{
public:
    std::string_view speak() const { return "Meow"; }
};

class Dog : public Animal
{
public:
    std::string_view speak() const { return "Woof"; }
};

void printSpeak(const Animal& a)
{
    std::cout << a.speak() << '\n';
}

int main()
{
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;

        if (type == "cat")
        {
            Cat c{};
            printSpeak(c);
        }
        else
        {
            Dog d{};
            printSpeak(d);
        }
    }

    return 0;
}

